using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // Breaking change: discriminator renamed from "Discriminator" to "$type".
            // Preserve old name so existing documents and raw SQL queries still work.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change: id no longer includes discriminator prefix.
            // Preserve old "Product|123" format for 500K existing documents.
            b.HasDiscriminatorInJsonId();

            // Breaking change: key property now maps directly to JSON "id",
            // removing the separate "Id" JSON property.
            // Preserve the shadow __id so the int Id property stays in the document.
            b.HasShadowId();

            // Breaking change: HasIndex now throws instead of being silently ignored.
            // Removed — Cosmos indexes all properties by default.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } = null!; }

