class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator still works because we configured
        // HasDiscriminator<string>("Discriminator") in the model.
        // Breaking change: EF9 now requires VALUE in projections for raw SQL.
        // Full-document SELECT * queries are unaffected.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Breaking change: sync I/O now throws InvalidOperationException.
        // Use async APIs exclusively.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

